UPDATE communication_templates 
SET subject = '{{tenant_name}} – Exciting News: Your New Online Platform is Live!',
    body_html = '<p>Dear {{user_name}} {{user_surname}}</p><p>We are pleased to announce that <strong>{{tenant_name}}</strong> has launched a brand-new web application designed to make your membership experience smoother and more convenient than ever before.</p><p>With this new platform, you will be able to initiate all your transactions online – deposits, withdrawals, switches, and more – saving you time and streamlining administration for everyone.</p><p>Your account has already been set up using your existing email address. To get started, simply click the button below to <strong>set your password</strong> and log in.</p><p>{{activation_link}}</p><h3>How to get started:</h3><ol><li><strong>Click the link above</strong> to set your new password.</li><li><strong>Log in</strong> with your email address and new password.</li><li><strong>Review your profile</strong> – check your personal details, upload any outstanding documents, and confirm your banking information.</li><li><strong>Start transacting</strong> – make deposits, view your portfolio, and manage your membership online.</li></ol><p style="background:#f8f9fa;border-left:4px solid #1a1a2e;padding:12px 16px;margin:16px 0;"><strong>A note from your admin team:</strong><br/>As with any new system, there may be occasional bugs or issues as we settle in. Your patience and understanding are greatly appreciated. If you experience any problems or have suggestions on how we can improve the platform, please do not hesitate to contact your administrator immediately. Your feedback is invaluable in helping us make this system the best it can be.</p><p>{{email_signature}}</p>'
WHERE id = '320f0ea0-7d35-4142-9f9f-241ffa4af43f';